SELECT T.*,
/* MODULE */ --C.SUBNAME_CH AS RACKID, RACK AS RACKID, CEIL(RN / 8) AS MODULENUM,
/* LEVEL */ CASE FLOOR(MOD(RN - 1, 8) / 2) WHEN 0 THEN 'A' WHEN 1 THEN 'B' WHEN 2 THEN 'C' WHEN 3 THEN 'D' END AS LEVELNAME,
/* POSITION */ MOD(RN - 1, 2) + 1 AS POSITIONNUM,
/* 최종 LOCATION 문자열 */ AREA || '-' || STORAGE || '-' || C.SUBNAME_CH || '-' || CEIL(RN / 8) || '-' || CASE FLOOR(MOD(RN - 1, 8) / 2) WHEN 0 THEN 'A' WHEN 1 THEN 'B' WHEN 2 THEN 'C' WHEN 3 THEN 'D' END || '-' || (MOD(RN - 1, 2) + 1) AS LOCATION, 'occupied' AS POSITIONSTATUS
FROM ( SELECT L.IID,L.SDATE,L.USEYN,L.YMDHMS,L.BARCODE,L.ITEMCODE,L.QTY,L.MEMO,L.LOGINID,L.FACTORY AS AREA,L.STORAGE,L.SOURCE,L.OKYN,L.RACK, ROW_NUMBER() OVER (ORDER BY YMDHMS) AS RN FROM t_wms_location L INNER JOIN T_MI_ITEM B ON L.ITEMCODE = B.ITEMCODE INNER JOIN t_mi_typesub C ON B.carno = C.subcode AND C.typecode = 'MI041' WHERE UPPER(C.SUBNAME_CH) = #{rackId} AND UPPER(STORAGE) = UPPER(#{storage}) AND UPPER(L.FACTORY) = #{factory} AND USEYN = 'Y' ) T INNER JOIN T_MI_ITEM B ON T.ITEMCODE = B.ITEMCODE INNER JOIN t_mi_typesub C ON B.carno = C.subcode AND C.typecode = 'MI041' ORDER BY RN

SELECT COUNT(*) FROM T_WMS_WORKLOCATION
WHERE 
	UPPER(FACTORY) = UPPER(#{factory})
	AND STORAGE = #{storage}
	AND RACK = #{rackId}

SELECT scantype, a.sdate, c.subname_ch AS car, b.spec as oitemcode, b.itemname, a.qty, a.type, a.barcode, a.location, a.lotdate, ymdhms FROM t_wms_realstock a LEFT OUTER JOIN t_mi_item b ON a.itemcode = b.itemcode AND deldate = ' ' LEFT OUTER JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' where 1=1 and useyn = 'Y'
and a.sdate = #{sdate}
and factory = #{factory}
and storage = #{storage}
and a.scantype = #{scantype}
order by iid desc

SELECT a.SDATE, a.itemcode, a.STORAGE, a.FACTORY, SUM(a.QTY) as sumqty, a.scantype FROM T_WMS_REALSTOCK a LEFT OUTER JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT OUTER JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' WHERE a.useyn = 'Y'
and a.sdate = #{sdate}
and a.factory = #{factory}
and a.storage = #{storage}
and a.itemcode = #{itemCode}
and a.scantype = #{scantype}
GROUP BY a.SDATE, a.itemcode, a.STORAGE, a.FACTORY, a.scantype

select a.iid, a.oitemcode, to_number(a.qty) as qty, nvl(a.source,' ') as source, a.storage, substr(a.ymdhms,9,6) as time from t_wms_inbound a left outer join t_wms_location b on a.barcode = b.barcode and b.useyn ='Y' where a.sdate = #{date} and a.storage = #{storage}
and a.custcode = #{custcode}
and a.custname = #{custname}
and a.source = 'INCOMING' and a.factory = #{factory} and a.useyn = 'Y' order by a.ymdhms desc

		SELECT
			a.sdate,
		    a.factory,
            a.storage,
            a.oitemcode,
		    SUM(a.qty) as sumqty
		  FROM t_wms_inbound a
		 WHERE a.useyn = 'Y'
		 	AND A.SOURCE = 'INCOMING'
		   AND a.sdate = #{date}
		   AND a.storage = #{storage}
		   AND a.factory = #{factory}

			AND a.custcode = #{custcode}


			AND a.custname = #{custname}

           GROUP BY a.sdate, a.oitemcode, a.factory, a.storage

select barcode from t_wms_unpack where barcode in
#{barcode}
and useyn = 'Y'

select sdate, a.barcode, qty,ymdhms, print_yn, print_qty as qty1, b.itemcode, b.itemname, c.subname_ch as car, lotdate, nvl((select sum(qty) from t_scm_barcode aa where a.barcode = aa.unpackbarcode and useyn = 'Y'),0) as scanqty, (select nvl(sum(qty),0) from t_wms_workmove bb where bb.barcode in ( select aa.barcode from t_scm_barcode aa where a.barcode = aa.unpackbarcode )) as workmoveqty , (select nvl(sum(qty),0) from t_wms_location bb where bb.barcode in ( select aa.barcode from t_scm_barcode aa where a.barcode = aa.unpackbarcode )) as locationqty from t_wms_unpack a left outer join t_mi_item b on a.itemcode = b.itemcode left outer join t_mi_typesub c on b.carno = c.subcode and c.typecode = 'MI041' where sdate = #{date} and useyn = 'Y' and a.factory = #{factory}
and barcode = #{barcode}
order by ymdhms desc

