WITH ref AS ( SELECT b.itemcode, MIN(TO_DATE(b.sdate,'YYYY-MM-DD')) AS ref_indate FROM t_scm_barcode b WHERE b.barcode IN
#{b}
GROUP BY b.itemcode ), agg AS ( SELECT l.itemcode, l.barcode, b.sdate, SUM(NVL(l.qty, 0)) AS qty FROM t_wms_location l JOIN ref r ON r.itemcode = l.itemcode left join t_scm_barcode b on b.barcode = l.barcode WHERE l.useyn = 'Y' AND l.factory = #{factory} AND L.STORAGE = #{storage1} AND TO_DATE(b.sdate,'YYYY-MM-DD') < r.ref_indate GROUP BY l.itemcode, l.barcode, b.sdate ), ranked AS ( SELECT a.*, ROW_NUMBER() OVER ( PARTITION BY a.itemcode ORDER BY TO_DATE(a.sdate,'YYYY-MM-DD') ASC, a.barcode ) AS rn FROM agg a ) SELECT r.itemcode, r.barcode, r.qty, r.sdate, m.spec AS oitemcode FROM ranked r LEFT JOIN t_mi_item m ON m.itemcode = r.itemcode AND m.deldate = ' ' WHERE r.rn <= 5 ORDER BY r.itemcode, TO_DATE(r.sdate,'YYYY-MM-DD') ASC, r.rn

