WITH ref AS ( SELECT l.itemcode, MIN(TO_DATE(l.indate,'YYYY-MM-DD')) AS ref_indate FROM t_wms_location l WHERE l.useyn = 'Y' AND l.barcode IN
#{b}
GROUP BY l.itemcode ), agg AS ( SELECT l.itemcode, l.location, l.indate, -- 문자열 그대로 보유 SUM( NVL( /* QTY가 NUMBER면 l.qty, 문자면 아래 TO_NUMBER 사용 */ l.qty -- TO_NUMBER(REPLACE(l.qty, ',', '')) ,0) ) AS qty FROM t_wms_location l JOIN ref r ON r.itemcode = l.itemcode WHERE l.useyn = 'Y' and factory = #{factory} AND TO_DATE(l.indate,'YYYY-MM-DD') < r.ref_indate GROUP BY l.itemcode, l.location, l.indate ), ranked AS ( SELECT a.*, ROW_NUMBER() OVER ( PARTITION BY a.itemcode ORDER BY TO_DATE(a.indate,'YYYY-MM-DD') ASC, a.location ) AS rn FROM agg a ) SELECT itemcode, location, qty, indate FROM ranked WHERE rn <= 5 ORDER BY itemcode, TO_DATE(indate,'YYYY-MM-DD') ASC, rn

