mapper.insert:
insert into t_wms_location(
	indate, ymdhms, location, barcode, itemcode, qty, loginid, factory, storage,source, memo2,okyn
)
select #{date}, TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'),#{location2},#{barcode},#{itemcode},#{qty},#{loginid},#{factory2},#{storage2},#{source},#{memo},#{okyn}
from dual
where not exists(
	select 1 from t_wms_location where factory = #{factory2} and useyn = 'Y' AND BARCODE = #{barcode}
)

